var list=[],len=datalist.length;
if(len>1){
	for(var i=1;i<len;i++){
		var temp=datalist[i].match(/<a href="(.*)">(.*)<\/a>/);
		list.push({
			"chapterName":temp[2],
			"chapterUrl":temp[1]
		});
	}
}
list;

