        var r = 4 * e;
        t.clamp(),
        t.sigBytes += r - (t.sigBytes % r || r)
    },
    unpad: function(t) {
        for (var e = t.words,
        r = t.sigBytes - 1; ! (e[r >>> 2] >>> 24 - r % 4 * 8 & 255);) r--;
        t.sigBytes = r + 1
    }
};

function showChapter(t) {
    var e = CryptoJS.enc.Latin1.parse("1234567812345678"),
    r = CryptoJS.enc.Latin1.parse("1234567812345676");
    return CryptoJS.AES.decrypt(t.trim(), e, {
        iv: r,
        padding: CryptoJS.pad.ZeroPadding
    }).toString(CryptoJS.enc.Utf8)
}

