ruleSearch.lastChapter:
@js:
last=JSON.parse(java.ajax('https://app-cdn.jjwxc.net/androidapi/chapterList?novelId='+java.get('id'))).chapterlist;
if(last){
last=last[last.length-1];
vip=last.isvip!=0?"🔒":'';
