$.chaptername
@js:
vip='{{$.isvip}}'!='0';
lock='{{$.islock}}'!='0';
type='{{$.chaptertype}}'=='1';
num=!type?'{{$.chapterid}}.':'';
result=type?'📖'+result+'📖':result;
v=vip?'◎':'';l=lock?'[锁]':'';
result=v+num+result+l;

